-- MIGRATION: colunas novas na tabela sales (rodar ANTES da carga se o banco
-- já existia com o schema antigo)
-- ═══════════════════════════════════════════════════════════════════════════

-- Adiciona as novas colunas (safe: IF NOT EXISTS)
ALTER TABLE sales ADD COLUMN IF NOT EXISTS location_id uuid REFERENCES locations(id);
ALTER TABLE sales ADD COLUMN IF NOT EXISTS card_brand text DEFAULT '';
ALTER TABLE sales ADD COLUMN IF NOT EXISTS net_amount numeric DEFAULT 0;
ALTER TABLE sales ADD COLUMN IF NOT EXISTS down_payment_amount numeric DEFAULT 0;
ALTER TABLE sales ADD COLUMN IF NOT EXISTS down_payment_method text DEFAULT '';
ALTER TABLE sales ADD COLUMN IF NOT EXISTS notes text DEFAULT '';

-- Cria a tabela de locais (se não existir)
CREATE TABLE IF NOT EXISTS locations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  is_default boolean DEFAULT false
);

-- RLS
ALTER TABLE locations ENABLE ROW LEVEL SECURITY;
CREATE POLICY IF NOT EXISTS "auth users" ON locations FOR ALL USING (auth.role() = 'authenticated');

